RED.editor.mermaid = (function () {
    let initializing = false
    let loaded = false
    let pendingEvals = []
    let diagramIds = 0

    function render(selector = '.mermaid') {
        // $(selector).hide()
        if (!loaded) {
            pendingEvals.push(selector)
            
            if (!initializing) {
                initializing = true
                // Find the cache-buster:
                let cacheBuster
                $('script').each(function (i, el) { 
                    if (!cacheBuster) {
                        const src = el.getAttribute('src')
                        const m = /\?v=(.+)$/.exec(src)
                        if (m) {
                            cacheBuster = m[1]
                        }
                    }
                })
                $.ajax({
                    url: `vendor/mermaid/mermaid.min.js?v=${cacheBuster}`,
                    dataType: "script",
                    cache: true,
                    success: function (data, stat, jqxhr) {
                        var isDark = document.documentElement.classList.contains('nr-theme-dark');
                        mermaid.initialize({
                            startOnLoad: false,
                            theme: isDark ? 'dark' : (RED.settings.get('mermaid', {}).theme || 'default')
                        })
                        loaded = true
                        while(pendingEvals.length > 0) {
                            const pending = pendingEvals.shift()
                            render(pending)
                        }
                    }
                });
            }
        } else {
            const nodes = document.querySelectorAll(selector)

            nodes.forEach(async node => {
                if (!node.getAttribute('mermaid-processed')) {
                    const mermaidContent = atob($(node).data('c64'))
                    node.setAttribute('mermaid-processed', true)
                    try {
                        const { svg } = await mermaid.render('mermaid-render-'+Date.now()+'-'+(diagramIds++), mermaidContent);
                        node.innerHTML = svg
                    } catch (err) {
                        $('<div>').css({
                            fontSize: '0.8em',
                            border: '1px solid var(--red-ui-border-color-error)',
                            padding: '5px',
                            marginBottom: '10px',
                        }).text(err.toString()).prependTo(node)
                    }
                }
            })
        }
    }  
    function setTheme(isDark) {
        if (!loaded) { return; }
        mermaid.initialize({
            startOnLoad: false,
            theme: isDark ? 'dark' : (RED.settings.get('mermaid', {}).theme || 'default')
        });
        // Clear processed flags and re-render visible diagrams
        document.querySelectorAll('.mermaid[mermaid-processed]').forEach(function(node) {
            node.removeAttribute('mermaid-processed');
            node.innerHTML = '';
        });
        render();
    }

    return {
        render: render,
        setTheme: setTheme,
    };
})();
